import { useLocation, useNavigate } from "react-router-dom";
import { useState } from "react";
import axios from "axios";
import "./styles/BookDetails.css";

function BookDetails() {
  const navigate = useNavigate();
  const location = useLocation();
  const book = location.state?.book;

  const userId = localStorage.getItem("userId");
  const [successMessage, setSuccessMessage] = useState("");

  const borrowBook = async () => {
    try {
      if (!userId) {
        alert("Please login first.");
        return;
      }

      await axios.post(
        "http://localhost:5000/api/transactions/borrow",
        {
          studentId: userId,
          bookId: book._id,
        }
      );

      setSuccessMessage("Book borrowed successfully!");
      setTimeout(() => {
        navigate("/mybooks");
      }, 1500);
    } catch (err) {
      alert(err.response?.data?.message || "Error borrowing book");
    }
  };

  if (!book) {
    return (
      <div className="book-detail-page">
        <div className="detail-card">
          <h2>Book not found</h2>
          <button className="back-btn" onClick={() => navigate(-1)}>
            ← Back
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="book-detail-page">
      <div className="detail-layout-container">
        <div className="detail-card">
          <img src={book.cover} alt={book.title} />

          <h2>{book.title}</h2>
          <p className="author">{book.author}</p>

          <p className="status">Status: <span className="avail">Available</span></p>

          {successMessage && <div className="success-toast">{successMessage}</div>}

          <div className="action-buttons">
            <button className="borrow-btn" onClick={borrowBook}>Borrow Book</button>
            <button className="back-btn" onClick={() => navigate(-1)}>
              ← Back
            </button>
          </div>
        </div>

        {(book.about || book.authorInfo) && (
          <div className="book-extra-section">
            {book.about && (
              <div className="extra-info-block">
                <h3>About the Book</h3>
                <p>{book.about}</p>
              </div>
            )}
            {book.authorInfo && (
              <div className="extra-info-block">
                <h3>About the Author</h3>
                <p>{book.authorInfo}</p>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
}

export default BookDetails;
